#include <bits/stdc++.h>
using namespace std;
int m, n;
vector<vector<char>> board;
string word;
bool dfs(int i, int j, int k) {
    if (k == word.size()) return true;
    if (i < 0 || i >= m || j < 0 || j >= n || word[k] != board[i][j]) return false;
    char temp = board[i][j];
    board[i][j] = '#';
    bool found = dfs(i + 1, j, k + 1) || dfs(i - 1, j, k + 1) || dfs(i, j + 1, k + 1) || dfs(i, j - 1, k + 1);
    board[i][j] = temp;
    return found;
}
int main() {
    cin >> m >> n;
    board.resize(m, vector<char>(n));
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            cin >> board[i][j];
        }
    }
    cin >> word;
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (dfs(i, j, 0)) {
                cout << "true" << endl;
                return 0;
            }
        }
    }
    cout << "false" << endl;
    return 0;
}
